subroutine RFSC1_2(F2, S3, COUP, M1, W1,R1)
use aloha_object
implicit none
 complex*16 CI
 parameter (CI=(0d0,1d0))
 complex*16 COUP
 type(aloha) F2
 integer flv_index2 
 real*8 M1
 real*8 OM1
 real*8 P1(0:3)
 type(aloha2d) R1
 type(aloha) S3
 real*8 W1
 complex*16 denom
    OM1 = 0d0
    if (M1.ne.0d0) OM1=1d0/M1**2
    R1%P(:) = +F2%P(:)+S3%P(:)
P1(:) = -R1 % P (:)
    denom = COUP/(P1(0)**2-P1(1)**2-P1(2)**2-P1(3)**2 - M1 * (M1 -CI* W1))
    R1%W(1)= denom*1d0/3d0 * CI * M1*S3 % W(1)*(OM1*(P1(0)*(F2 % W(3)*(M1*M1*OM1*(-P1(0)+P1(3))+(+2d0*(P1(0))-P1(3)))+F2 % W(4)*(M1*M1*OM1*(P1(1)-CI*(P1(2)))+(-P1(1)+CI*(P1(2)))))-F2 % W(3)*(P1(3)*P1(3)+P1(1)*P1(1)+P1(2)*P1(2)))-F2 % W(3))
    R1%W(2)= denom*1d0/3d0 * CI * M1*S3 % W(1)*(OM1*(P1(0)*(F2 % W(3)*(M1*M1*OM1*(P1(1)+CI*(P1(2)))+(-P1(1)-CI*(P1(2))))+F2 % W(4)*(M1*-M1*OM1*(P1(0)+P1(3))+(+2d0*(P1(0))+P1(3))))-F2 % W(4)*(P1(1)*P1(1)+P1(2)*P1(2)+P1(3)*P1(3)))-F2 % W(4))
    R1%W(3)= denom*CI * S3 % W(1)*(F2 % W(3)*(OM1*(P1(0)*(M1*M1*(OM1*(-1d0/3d0)*(-P1(0)*P1(0)+P1(3)*P1(3)+P1(1)*P1(1)+P1(2)*P1(2))+ -5d0/3d0)+(-P1(0)*P1(0)+P1(3)*P1(3)+P1(1)*P1(1)+P1(2)*P1(2)))+1d0/3d0*(P1(3)*M1*M1))+(+7d0/3d0*(P1(0))-1d0/3d0*(P1(3))))+F2 % W(4)*(M1*1d0/3d0 * M1*OM1*(P1(1)-CI*(P1(2)))+(-1d0/3d0*(P1(1))+1d0/3d0 * CI*(P1(2)))))
    R1%W(4)= denom*CI * S3 % W(1)*(F2 % W(4)*(OM1*(P1(0)*(M1*M1*(OM1*(-1d0/3d0)*(P1(1)*P1(1)+P1(2)*P1(2)+P1(3)*P1(3)-P1(0)*P1(0))+ -5d0/3d0)+(P1(1)*P1(1)+P1(2)*P1(2)+P1(3)*P1(3)-P1(0)*P1(0)))-1d0/3d0*(P1(3)*M1*M1))+(+7d0/3d0*(P1(0))+1d0/3d0*(P1(3))))+F2 % W(3)*(M1*1d0/3d0 * M1*OM1*(P1(1)+CI*(P1(2)))+(-1d0/3d0*(P1(1))-1d0/3d0 * CI*(P1(2)))))
    R1%W(5)= denom*(-1d0/3d0 )* CI * M1*S3 % W(1)*(OM1*(P1(1)*(F2 % W(3)*(M1*M1*OM1*(P1(0)-P1(3))+(-P1(0)+P1(3)))+F2 % W(4)*(M1*M1*OM1*(-P1(1)+CI*(P1(2)))+(+2d0*(P1(1))-CI*(P1(2)))))+F2 % W(4)*(P1(2)*P1(2)+P1(3)*P1(3)-P1(0)*P1(0)))+F2 % W(4))
    R1%W(6)= denom*(-1d0/3d0 )* CI * M1*S3 % W(1)*(OM1*(P1(1)*(F2 % W(3)*(M1*-M1*OM1*(P1(1)+CI*(P1(2)))+(+2d0*(P1(1))+CI*(P1(2))))+F2 % W(4)*(M1*M1*OM1*(P1(0)+P1(3))+(-P1(0)-P1(3))))+F2 % W(3)*(-P1(0)*P1(0)+P1(3)*P1(3)+P1(2)*P1(2)))+F2 % W(3))
    R1%W(7)= denom*CI * S3 % W(1)*(F2 % W(3)*(OM1*(P1(1)*(M1*M1*(OM1*(-1d0/3d0)*(-P1(0)*P1(0)+P1(3)*P1(3)+P1(1)*P1(1)+P1(2)*P1(2))+ -5d0/3d0)+(-P1(0)*P1(0)+P1(3)*P1(3)+P1(1)*P1(1)+P1(2)*P1(2)))-1d0/3d0 * CI*(P1(2)*M1*M1))+(+7d0/3d0*(P1(1))+1d0/3d0 * CI*(P1(2))))+F2 % W(4)*(M1*1d0/3d0 * M1*OM1*(P1(0)+P1(3))+(-1d0/3d0*(P1(0)+P1(3)))))
    R1%W(8)= denom*CI * S3 % W(1)*(F2 % W(4)*(OM1*(P1(1)*(M1*M1*(OM1*(-1d0/3d0)*(P1(1)*P1(1)+P1(2)*P1(2)+P1(3)*P1(3)-P1(0)*P1(0))+ -5d0/3d0)+(P1(1)*P1(1)+P1(2)*P1(2)+P1(3)*P1(3)-P1(0)*P1(0)))+1d0/3d0 * CI*(P1(2)*M1*M1))+(+7d0/3d0*(P1(1))-1d0/3d0 * CI*(P1(2))))+F2 % W(3)*(M1*1d0/3d0 * M1*OM1*(P1(0)-P1(3))+(-1d0/3d0*(P1(0))+1d0/3d0*(P1(3)))))
    R1%W(9)= denom*(-1d0/3d0 )* M1*S3 % W(1)*(OM1*(P1(2)*(F2 % W(3)*(M1*M1*OM1*(+CI*(P1(0))-CI*(P1(3)))+(-CI*(P1(0))+CI*(P1(3))))+F2 % W(4)*(M1*-M1*OM1*(+CI*(P1(1))+P1(2))+(+CI*(P1(1))+2d0*(P1(2)))))+F2 % W(4)*(P1(1)*P1(1)+P1(3)*P1(3)-P1(0)*P1(0)))+F2 % W(4))
    R1%W(10)= denom*1d0/3d0 * M1*S3 % W(1)*(OM1*(P1(2)*(F2 % W(3)*(M1*M1*OM1*(+CI*(P1(1))-P1(2))+(-CI*(P1(1))+2d0*(P1(2))))+F2 % W(4)*(M1*-M1*OM1*(+CI*(P1(0)+P1(3)))+(+CI*(P1(0)+P1(3)))))+F2 % W(3)*(-P1(0)*P1(0)+P1(3)*P1(3)+P1(1)*P1(1)))+F2 % W(3))
    R1%W(11)= denom*1d0/3d0 * S3 % W(1)*(F2 % W(3)*(OM1*(P1(2)*(M1*M1*(OM1*(-1d0)*(-CI*(P1(0)*P1(0))+CI*(P1(3)*P1(3)+P1(1)*P1(1)+P1(2)*P1(2)))+ -5d0 * CI)+(-3d0 * CI*(P1(0)*P1(0))+3d0 * CI*(P1(3)*P1(3)+P1(1)*P1(1)+P1(2)*P1(2))))-P1(1)*M1*M1)+(P1(1)+7d0 * CI*(P1(2))))+F2 % W(4)*(M1*M1*OM1*(P1(0)+P1(3))+(-P1(0)-P1(3))))
    R1%W(12)= denom*(-1d0/3d0 )* S3 % W(1)*(F2 % W(4)*(OM1*(P1(2)*(M1*M1*(OM1*(+CI*(P1(1)*P1(1)+P1(2)*P1(2)+P1(3)*P1(3))-CI*(P1(0)*P1(0)))+ 5d0 * CI)+(-3d0 * CI*(P1(1)*P1(1)+P1(2)*P1(2)+P1(3)*P1(3))+3d0 * CI*(P1(0)*P1(0))))-P1(1)*M1*M1)+(P1(1)-7d0 * CI*(P1(2))))+F2 % W(3)*(M1*M1*OM1*(P1(0)-P1(3))+(-P1(0)+P1(3))))
    R1%W(13)= denom*(-1d0/3d0 )* CI * M1*S3 % W(1)*(OM1*(P1(3)*(F2 % W(3)*(M1*M1*OM1*(P1(0)-P1(3))+(-P1(0)+2d0*(P1(3))))+F2 % W(4)*(M1*M1*OM1*(-P1(1)+CI*(P1(2)))+(P1(1)-CI*(P1(2)))))+F2 % W(3)*(-P1(0)*P1(0)+P1(1)*P1(1)+P1(2)*P1(2)))+F2 % W(3))
    R1%W(14)= denom*1d0/3d0 * CI * M1*S3 % W(1)*(OM1*(P1(3)*(F2 % W(3)*(M1*M1*OM1*(P1(1)+CI*(P1(2)))+(-P1(1)-CI*(P1(2))))+F2 % W(4)*(M1*-M1*OM1*(P1(0)+P1(3))+(P1(0)+2d0*(P1(3)))))+F2 % W(4)*(P1(1)*P1(1)+P1(2)*P1(2)-P1(0)*P1(0)))+F2 % W(4))
    R1%W(15)= denom*CI * S3 % W(1)*(F2 % W(3)*(OM1*(P1(3)*(M1*M1*(OM1*(-1d0/3d0)*(-P1(0)*P1(0)+P1(3)*P1(3)+P1(1)*P1(1)+P1(2)*P1(2))+ -5d0/3d0)+(-P1(0)*P1(0)+P1(3)*P1(3)+P1(1)*P1(1)+P1(2)*P1(2)))+1d0/3d0*(P1(0)*M1*M1))+(-1d0/3d0*(P1(0))+7d0/3d0*(P1(3))))+F2 % W(4)*(M1*1d0/3d0 * M1*OM1*(-P1(1)+CI*(P1(2)))+(+1d0/3d0*(P1(1))-1d0/3d0 * CI*(P1(2)))))
    R1%W(16)= denom*CI * S3 % W(1)*(F2 % W(4)*(OM1*(P1(3)*(M1*M1*(OM1*(-1d0/3d0)*(P1(1)*P1(1)+P1(2)*P1(2)+P1(3)*P1(3)-P1(0)*P1(0))+ -5d0/3d0)+(P1(1)*P1(1)+P1(2)*P1(2)+P1(3)*P1(3)-P1(0)*P1(0)))-1d0/3d0*(P1(0)*M1*M1))+(+1d0/3d0*(P1(0))+7d0/3d0*(P1(3))))+F2 % W(3)*(M1*1d0/3d0 * M1*OM1*(P1(1)+CI*(P1(2)))+(-1d0/3d0*(P1(1))-1d0/3d0 * CI*(P1(2)))))
 end


